  "pricing.starter.title": "Starter", "pricing.starter.blurb": "Kwa NGOs ndogo zinazoanza na utafiti wa sauti.", "pricing.starter.cta": "Anza",
  "pricing.popular": "Maarufu zaidi",
  "pricing.pro.title": "Professional", "pricing.pro.blurb": "Kwa mashirika ya kati yenye kampeni nyingi.", "pricing.pro.cta": "Omba Demo",
  "pricing.ent.title": "Enterprise", "pricing.ent.blurb": "INGOs kubwa na serikali, na hifadhi ya ndani (on-prem).", "pricing.ent.cta": "Wasiliana Nasi",
